// Current language state — stored on window so all script files share the same reference
window.currentLang = localStorage.getItem('mineguard_lang') || 'en';

function t(key) {
  return (window.TRANSLATIONS[window.currentLang] && window.TRANSLATIONS[window.currentLang][key]) || window.TRANSLATIONS['en'][key] || key;
}

function setLanguage(lang) {
  window.currentLang = lang;
  localStorage.setItem('mineguard_lang', lang);
}

function getPPEItems() {
  return window.currentLang === 'fr' ? window.PPE_ITEMS_FR : PPE_ITEMS;
}

function getSafetyTips() {
  return window.currentLang === 'fr' ? window.SAFETY_TIPS_FR : SAFETY_TIPS;
}

function getFirstAidGuides() {
  return window.currentLang === 'fr' ? window.FIRST_AID_GUIDES_FR : FIRST_AID_GUIDES;
}

function getEmergencyContacts() {
  return window.currentLang === 'fr' ? window.EMERGENCY_CONTACTS_FR : EMERGENCY_CONTACTS;
}

// ============================================
// FRENCH GLOSSARY TERMS (229 terms A–Z)
// Parallel structure to GLOSSARY_TERMS in data.js
// Assigned to window so app.js can access it
// ============================================

window.GLOSSARY_TERMS_FR = [
  // A
  { term: "Accès Horizontal (Adit)", short: "Entrée horizontale de mine", definition: "Un passage ou tunnel horizontal creusé dans le flanc d'une colline ou d'une montagne pour accéder à une mine. Contrairement à un puits, un adit est percé au niveau de la surface et ne nécessite pas d'équipement de levage.", category: "Structures Minières" },
  { term: "Exploitation Alluvionnaire", short: "Extraction en lits de rivières", definition: "L'extraction de minéraux déposés par l'action de l'eau dans les lits de rivières, les plaines d'inondation ou les anciens chenaux. L'orpaillage alluvionnaire est courant en Afrique de l'Ouest.", category: "Méthodes d'Exploitation" },
  { term: "Angle de Repos", short: "Angle de pente stable maximum", definition: "L'angle le plus raide auquel un matériau — comme les stériles ou le sol — peut être empilé sans glisser. Dépasser l'angle de repos provoque des ruptures de pente et des glissements de terrain dangereux.", category: "Géotechnique" },
  { term: "Exploitation Artisanale", short: "Extraction informelle à petite échelle", definition: "Exploitation minière à petite échelle, informelle, réalisée par des individus ou de petits groupes avec des outils basiques. Souvent non réglementée, elle présente des risques importants pour la sécurité et l'environnement.", category: "Méthodes d'Exploitation" },
  { term: "Dosage (Assay)", short: "Test chimique de qualité du minerai", definition: "Une analyse chimique d'échantillons de minerai ou de minéraux pour déterminer la teneur et la qualité des métaux ou minéraux précieux présents. Les résultats guident la planification de la mine et les décisions de traitement.", category: "Tests et Analyses" },
  { term: "Personne Autorisée", short: "Travailleur minier certifié", definition: "Une personne désignée par le directeur de mine comme compétente et autorisée à effectuer des tâches spécifiques ou à entrer dans des zones spécifiques du site minier.", category: "Sécurité et Personnel" },
  { term: "Téléphérique (Aerial Tramway)", short: "Transport de matériaux en hauteur", definition: "Un système supporté par des câbles utilisé pour transporter du minerai, de l'équipement ou du personnel entre différentes élévations sur un site minier, notamment en terrain montagneux ou escarpé.", category: "Équipements Miniers" },
  { term: "Drainage Minier Acide (DMA)", short: "Eau minière acide toxique", definition: "L'eau qui devient acide après avoir réagi avec les minéraux sulfurés exposés lors de l'exploitation minière. Le DMA est l'un des dangers environnementaux les plus graves dans l'industrie minière.", category: "Environnement" },
  { term: "Jambe à Air Comprimé (Airleg)", short: "Support pneumatique de foreuse", definition: "Un dispositif pneumatique utilisé pour supporter et alimenter une foreuse lors des opérations de forage souterrain. Il permet à l'opérateur de contrôler la poussée et la direction du trépan.", category: "Équipements Miniers" },

  // B
  { term: "Remblayage (Backfill)", short: "Matériau de remplissage de vide", definition: "Matériau utilisé pour combler les zones excavées ou les vides dans une mine. Le remblayage supporte la roche environnante, contrôle l'affaissement et peut être constitué de stériles, de résidus ou de pâte cimentée.", category: "Soutènement du Sol" },
  { term: "Zone Stérile", short: "Zone rocheuse sans minerai", definition: "Une section de roche au sein ou autour d'un gisement minéral qui contient peu ou pas de teneur en minéraux économiques. Les zones stériles doivent être identifiées et séparées du minerai pendant l'exploitation.", category: "Géologie" },
  { term: "Gradin (Bench)", short: "Marche horizontale de mine", definition: "Un rebord ou une marche horizontale dans une mine à ciel ouvert. Les gradins sont travaillés progressivement vers le bas et fournissent des plateformes pour les opérations de forage, dynamitage, chargement et transport.", category: "Mine à Ciel Ouvert" },
  { term: "Hauteur de Gradin", short: "Mesure verticale de l'étape", definition: "La distance verticale entre deux niveaux de gradin adjacents dans une mine à ciel ouvert. La hauteur de gradin est déterminée par le type d'équipement utilisé et les conditions de la roche.", category: "Mine à Ciel Ouvert" },
  { term: "Dynamitage (Blasting)", short: "Fragmentation contrôlée de la roche", definition: "L'utilisation contrôlée d'explosifs pour briser la roche ou le minerai dans les opérations minières. Nécessite des protocoles de sécurité stricts, du personnel de tir sous licence, des zones d'exclusion et des notifications de tir formelles.", category: "Forage et Dynamitage" },
  { term: "Trou de Mine (Blast Hole)", short: "Trou foré pour les explosifs", definition: "Un trou foré dans la roche dans lequel des explosifs sont chargés pour le dynamitage. Le diamètre, la profondeur et le schéma des trous de mine sont conçus en fonction des propriétés de la roche et de la granulométrie souhaitée.", category: "Forage et Dynamitage" },
  { term: "Schéma de Tir (Blast Pattern)", short: "Conception du plan de forage", definition: "L'arrangement géométrique des trous de mine sur un front ou un gradin, incluant l'espacement, la banquette et le décalage. Un schéma de tir bien conçu assure une fragmentation efficace et minimise les projections.", category: "Forage et Dynamitage" },
  { term: "Foudroyage par Blocs (Block Caving)", short: "Méthode minière souterraine massive", definition: "Une méthode d'exploitation souterraine où un grand bloc de minerai est sous-cavé pour lui permettre de s'effondrer par gravité. L'une des méthodes d'exploitation souterraine les moins coûteuses, utilisée pour les grands gisements à faible teneur.", category: "Méthodes d'Exploitation" },
  { term: "Sondage (Borehole)", short: "Trou d'exploration foré", definition: "Un trou étroit foré dans le sol à des fins d'exploration, d'approvisionnement en eau ou d'investigation géotechnique. Les échantillons de sondage fournissent des informations critiques sur la géologie et la qualité d'un gisement.", category: "Exploration" },
  { term: "Berme de Sécurité (Bund / Berm)", short: "Remblai de sécurité", definition: "Un mur de terre ou un remblai construit au bord des routes de transport, des crêtes de fosse et des bords de décharge pour empêcher les véhicules de tomber. La hauteur doit être au moins la moitié du diamètre de la roue du plus grand véhicule en opération.", category: "Structures de Sécurité" },
  { term: "Banquette (Burden)", short: "Roche entre trou et front", definition: "La distance entre la rangée avant des trous de mine et le front libre du gradin à dynamiter. Une banquette correcte est essentielle pour une fragmentation efficace et pour prévenir les projections.", category: "Forage et Dynamitage" },
  { term: "Lingot (Bullion)", short: "Barre de métal précieux raffiné", definition: "Une grande quantité de métal précieux, typiquement l'or ou l'argent, qui a été raffiné et coulé en barres ou lingots. Le lingot est le produit final de nombreuses opérations d'extraction d'or.", category: "Traitement" },

  // C
  { term: "Cage (Ascenseur de Mine)", short: "Élévateur souterrain de personnel", definition: "Un ascenseur fermé utilisé pour transporter travailleurs et matériaux dans un puits de mine. Doit être entretenu, testé régulièrement et opéré par un opérateur de treuil certifié.", category: "Équipements Miniers" },
  { term: "Roche de Couverture (Cap Rock)", short: "Roche surmontant le corps minéralisé", definition: "Roche dure directement au-dessus d'un corps minéralisé ou d'une formation plus molle. La roche de couverture doit être forée et dynamitée avant d'accéder au minerai en dessous.", category: "Géologie" },
  { term: "Carbone en Lixiviation (CIL)", short: "Procédé de récupération d'or", definition: "Une méthode de traitement de l'or où du charbon actif est ajouté à une boue de lixiviation au cyanure pour lixivier et adsorber simultanément l'or. L'une des techniques les plus courantes de récupération d'or.", category: "Traitement" },
  { term: "Berme de Retenue (Catch Berm)", short: "Gradin de retenue de chutes de roches", definition: "Une large marche plate creusée dans une paroi de fosse pour retenir les roches et débris tombants, empêchant le matériau d'atteindre les gradins inférieurs où travaillent les travailleurs et équipements.", category: "Soutènement du Sol" },
  { term: "Éboulement (Cave-in)", short: "Effondrement du sol", definition: "L'effondrement soudain et incontrôlé du toit, des parois ou du plancher dans une excavation minière. Les éboulements sont parmi les dangers les plus mortels dans l'exploitation minière souterraine.", category: "Dangers du Sol" },
  { term: "Remblai en Pâte Cimentée", short: "Mélange de remblayage", definition: "Un mélange de résidus, d'eau et de ciment utilisé comme remblai souterrain. Il fournit un soutien solide et stable pour les vides souterrains et prévient l'effondrement des zones exploitées.", category: "Soutènement du Sol" },
  { term: "Pilier en Chaîne", short: "Nervure de soutien non exploitée", definition: "Un long pilier étroit de minerai ou de roche non exploité laissé en place entre des excavations adjacentes pour fournir un soutien au toit et prévenir l'affaissement de surface.", category: "Soutènement du Sol" },
  { term: "Chalcopyrite", short: "Minéral sulfure de cuivre-fer", definition: "Un minéral sulfure de cuivre-fer (CuFeS2) et le minerai de cuivre le plus important. De couleur jaune laiton, il se trouve couramment dans de nombreux gisements de cuivre porphyrique.", category: "Géologie" },
  { term: "Collet (Collar)", short: "Sommet du trou de forage ou puits", definition: "Le sommet ou l'ouverture d'un trou de forage ou d'un puits de mine. Le collet doit être correctement tubé et sécurisé pour prévenir l'effondrement et soutenir l'équipement de forage ou de levage.", category: "Structures Minières" },
  { term: "Personne Compétente", short: "Superviseur de sécurité qualifié", definition: "Une personne possédant les qualifications, la formation et l'expérience appropriées pour identifier les dangers sur le lieu de travail et qui a l'autorité de prendre des mesures correctives immédiates.", category: "Sécurité et Personnel" },
  { term: "Espace Confiné", short: "Zone fermée restreinte", definition: "Un espace fermé ou partiellement fermé non conçu pour une occupation humaine continue, avec un accès/sortie restreint et pouvant avoir des atmosphères dangereuses. L'entrée nécessite un permis, un test de gaz et une personne de surveillance.", category: "Sécurité Minière" },
  { term: "Exploitation en Contour", short: "Exploitation minière en flanc de colline", definition: "Une technique d'exploitation à ciel ouvert utilisée en terrain vallonné où des coupes sont effectuées le long des lignes de contour naturelles du terrain pour accéder aux filons de charbon ou de minéraux.", category: "Méthodes d'Exploitation" },
  { term: "Carotte (Core Sample)", short: "Échantillon cylindrique de forage", definition: "Un échantillon cylindrique de roche extrait lors du forage au diamant pour l'analyse géologique. Les carottes révèlent le type de roche, la structure, la teneur en minéraux et la qualité d'un gisement.", category: "Exploration" },
  { term: "Concasseur (Crusher)", short: "Machine de réduction granulométrique", definition: "Une machine utilisée pour réduire la taille de la roche concassée ou du minerai en fragments plus petits pour un traitement ultérieur. Les types incluent les concasseurs à mâchoires, giratoires et à cône.", category: "Équipements Miniers" },
  { term: "Taille et Remblayage (Cut-and-Fill)", short: "Méthode d'extraction souterraine", definition: "Une méthode d'exploitation souterraine où le minerai est extrait en tranches horizontales et le vide est rempli de stériles ou de pâte cimentée avant que la tranche suivante ne soit exploitée au-dessus.", category: "Méthodes d'Exploitation" },
  { term: "Cyanure", short: "Produit chimique de lixiviation d'or", definition: "Un composé chimique toxique (cyanure de sodium ou de potassium) utilisé dans le traitement de l'or et de l'argent pour dissoudre les métaux précieux du minerai. Nécessite des procédures de manipulation strictes et des plans d'intervention en cas de déversement.", category: "Traitement" },
  { term: "Teneur de Coupure", short: "Teneur minimale économique du minerai", definition: "La teneur minimale en minéraux à partir de laquelle il est économiquement viable d'exploiter le minerai plutôt que de le traiter comme déchet. Le matériau en dessous de la teneur de coupure est stocké comme stérile.", category: "Contrôle de Qualité" },

  // D
  { term: "Terrain Mort", short: "Zone géologiquement stérile", definition: "Roche ou terrain ne contenant aucun minerai et économiquement improductif. Identifier le terrain mort tôt prévient les efforts miniers inutiles et réduit les coûts.", category: "Géologie" },
  { term: "Descenderie (Decline)", short: "Rampe d'accès souterraine", definition: "Un tunnel incliné creusé sous terre à un angle pour fournir un accès aux véhicules et équipements entre la surface et les travaux souterrains. Également appelé rampe.", category: "Structures Minières" },
  { term: "Détonateur", short: "Dispositif d'initiation explosive", definition: "Un dispositif utilisé pour initier la détonation d'une charge explosive. Les détonateurs sont extrêmement sensibles et ne doivent être manipulés que par des artificiers sous licence.", category: "Forage et Dynamitage" },
  { term: "Exhaure (Dewatering)", short: "Élimination d'eau de la mine", definition: "Le processus d'élimination de l'eau d'une mine pour maintenir des conditions de travail sûres. Les méthodes incluent les pompes submersibles, les galeries de drainage et les puisards. L'inondation non contrôlée est un danger majeur.", category: "Sécurité Minière" },
  { term: "Forage au Diamant", short: "Méthode de forage de carottes", definition: "Une technique de forage utilisant un trépan rotatif garni de diamants industriels pour couper des échantillons cylindriques de roche. Produit des données géologiques de haute qualité pour l'estimation des ressources.", category: "Exploration" },
  { term: "Dyke (Filon Éruptif)", short: "Formation rocheuse intrusive", definition: "Une feuille de roche ignée qui s'est introduite dans des formations rocheuses existantes. Les dykes peuvent affecter les schémas de tir, la stabilité des pentes et la distribution du minerai.", category: "Géologie" },
  { term: "Dilution", short: "Stériles mélangés au minerai", definition: "Le mélange non intentionnel de stériles ou de matériaux à faible teneur avec du minerai pendant le processus d'exploitation, ce qui réduit la teneur moyenne du matériau envoyé à l'usine de traitement.", category: "Contrôle de Qualité" },
  { term: "Pendage (Dip)", short: "Angle d'inclinaison de la couche rocheuse", definition: "L'angle auquel une couche rocheuse, un corps minéralisé ou une structure géologique s'incline sous la surface horizontale. Comprendre le pendage est essentiel pour la planification minière et l'analyse de stabilité des pentes.", category: "Géologie" },
  { term: "Bulldozer (Dozer)", short: "Machine de terrassement", definition: "Une puissante machine à chenilles équipée d'une lame avant utilisée pour pousser les stériles, niveler les routes de transport et construire des bermes sur les sites miniers.", category: "Équipements Miniers" },
  { term: "Dragline", short: "Grande excavatrice de surface", definition: "Une grande excavatrice de surface qui utilise un godet suspendu à une longue flèche pour creuser et déplacer de grands volumes de mort-terrain ou de matériaux.", category: "Équipements Miniers" },
  { term: "Galerie Horizontale (Drift)", short: "Tunnel horizontal souterrain", definition: "Un tunnel horizontal creusé sous terre, suivant généralement le gisement d'un corps minéralisé. Les galeries fournissent un accès pour le développement, la production et la ventilation dans les mines souterraines.", category: "Structures Minières" },
  { term: "Forage (Drilling)", short: "Processus de création de trous dans la roche", definition: "Le processus de création de trous dans la roche à des fins d'exploration, de dynamitage ou de soutènement. Le forage est une activité centrale sur chaque site minier et nécessite des opérateurs formés et un entretien régulier des équipements.", category: "Forage et Dynamitage" },
  { term: "Décharge (Dump)", short: "Zone d'élimination des stériles", definition: "Une zone désignée où les stériles, le mort-terrain ou d'autres matériaux non minéralisés sont déposés de façon permanente. Les décharges doivent être conçues pour la stabilité et gérées pour prévenir la contamination environnementale.", category: "Gestion des Déchets" },
  { term: "Suppression des Poussières", short: "Méthode de contrôle des poussières en suspension", definition: "Mesures prises pour réduire la quantité de poussière nocive dans l'air sur un site minier, notamment l'arrosage à l'eau, les suppresseurs chimiques et les installations de traitement fermées.", category: "Sécurité Minière" },
  { term: "Charge Dynamique", short: "Force d'impact due au mouvement", definition: "Forces générées par les équipements en mouvement, le dynamitage ou les mouvements de masse rocheuse qui s'ajoutent au poids statique sur les structures et les systèmes de soutènement.", category: "Ingénierie" },

  // E
  { term: "Mise à la Terre (Earthing)", short: "Connexion de sécurité électrique", definition: "La connexion des équipements électriques à la terre pour prévenir les chocs électriques. Tous les équipements électriques sur les sites miniers doivent être correctement mis à la terre et régulièrement testés par un électricien qualifié.", category: "Sécurité Minière" },
  { term: "Danger Électrique", short: "Danger lié à l'électricité", definition: "Tout risque de blessure, de mort ou de dommage aux équipements dû à l'électricité, y compris les câblages exposés, les lignes électriques aériennes, les orages électriques et les équipements sous tension.", category: "Sécurité Minière" },
  { term: "Zone d'Exclusion", short: "Zone de danger — accès interdit", definition: "Une zone définie autour d'un danger — comme une zone de tir, une pente instable ou une machine en fonctionnement — où l'entrée est strictement interdite au personnel non autorisé. Doit être clairement marquée.", category: "Sécurité Minière" },
  { term: "Exploration", short: "Recherche de gisements minéraux", definition: "L'investigation systématique d'une zone pour localiser et évaluer les gisements minéraux. Comprend la cartographie géologique, l'échantillonnage des sols, les levés géophysiques et le forage.", category: "Exploration" },
  { term: "Explosif", short: "Matériau à détonation contrôlée", definition: "Un composé chimique ou un mélange qui libère rapidement de l'énergie par détonation, utilisé pour fragmenter la roche dans l'exploitation minière. Les explosifs doivent être stockés dans des dépôts agréés.", category: "Forage et Dynamitage" },
  { term: "Excavatrice", short: "Machine hydraulique de creusement", definition: "Une machine hydraulique avec une flèche, un bras et un godet utilisée pour creuser et charger des matériaux dans les mines à ciel ouvert et souterraines.", category: "Équipements Miniers" },

  // F
  { term: "Front (Face)", short: "Surface d'excavation active", definition: "La surface de travail exposée dans une mine à partir de laquelle le minerai ou les stériles sont activement excavés. Le front est généralement la zone à risque le plus élevé sur un site minier.", category: "Structures Minières" },
  { term: "Chute de Roches (FOG)", short: "Effondrement incontrôlé de roche", definition: "La chute incontrôlée de roche, de sol ou de débris dans une excavation minière. L'une des principales causes de décès dans l'exploitation minière mondiale. La prévention nécessite un écaillage systématique et un soutènement.", category: "Dangers du Sol" },
  { term: "Faille (Fault)", short: "Fracture rocheuse avec mouvement", definition: "Une fracture ou zone de fractures dans la roche le long de laquelle un mouvement s'est produit. Les failles peuvent créer des conditions de sol instables, des venues d'eau inattendues et compliquer l'interprétation des corps minéralisés.", category: "Géologie" },
  { term: "Paroi Finale", short: "Pente de limite de fosse permanente", definition: "La dernière paroi de fosse qui restera après la fin de l'exploitation. Les parois finales sont conçues pour une stabilité à long terme et ne sont pas soumises à d'autres dynamitages.", category: "Mine à Ciel Ouvert" },
  { term: "Système Anti-Incendie", short: "Système automatique de lutte contre l'incendie", definition: "Un système automatique installé sur les équipements souterrains et dans les installations de traitement pour détecter et supprimer les incendies. Doit être régulièrement inspecté et entretenu.", category: "Sécurité Minière" },
  { term: "Flottation", short: "Procédé de séparation des minéraux", definition: "Une technique de traitement des minéraux qui utilise des bulles d'air et des réactifs chimiques pour séparer les particules de minéraux précieux des stériles dans une boue aqueuse.", category: "Traitement" },
  { term: "Projection de Tir (Flyrock)", short: "Projectile rocheux éjecté par le tir", definition: "Fragments de roche projetés au-delà de la zone de tir prévue lors d'un dynamitage. Les projections de tir sont une cause majeure de blessures et de décès liés au dynamitage.", category: "Forage et Dynamitage" },
  { term: "Mur Inférieur (Footwall)", short: "Roche sous le corps minéralisé", definition: "La masse rocheuse se trouvant sous un corps minéralisé ou un filon incliné. Dans l'exploitation souterraine, le mur inférieur forme le plancher d'un chantier ou d'une galerie suivant le corps minéralisé.", category: "Géologie" },
  { term: "Front Libre", short: "Surface de roche exposée pour le tir", definition: "Une surface exposée de roche vers laquelle l'énergie de dynamitage est dirigée. Chaque tir efficace nécessite au moins un front libre vers lequel le matériau peut se déplacer pendant la détonation.", category: "Forage et Dynamitage" },
  { term: "Poussières Fugitives", short: "Poussières en suspension non contrôlées", definition: "Poussière qui s'échappe dans l'atmosphère depuis les routes non revêtues, le dynamitage, le concassage, les stocks de matériaux et l'érosion éolienne sur les sites miniers.", category: "Environnement" },

  // G
  { term: "Gangue (Stérile)", short: "Roche sans valeur dans le minerai", definition: "La roche ou le matériau minéral commercialement sans valeur qui entoure ou est mélangé avec le minerai précieux dans un gisement. La gangue doit être séparée du minerai pendant le traitement.", category: "Géologie" },
  { term: "Détection de Gaz", short: "Surveillance des risques atmosphériques", definition: "La surveillance continue ou périodique de l'air souterrain pour les gaz dangereux incluant le monoxyde de carbone, le méthane, le sulfure d'hydrogène et le déficit en oxygène.", category: "Sécurité Minière" },
  { term: "Géologue", short: "Scientifique des roches et minéraux", definition: "Un scientifique qui étudie les formations rocheuses, les gisements minéraux et les structures géologiques de la terre. Les géologues de mine guident les programmes de forage et les activités de contrôle de qualité.", category: "Sécurité et Personnel" },
  { term: "Géotechnique", short: "Ingénierie des roches et sols", definition: "La discipline d'ingénierie qui étudie le comportement de la roche et du sol sous contrainte. En exploitation minière, les ingénieurs géotechniciens conçoivent les pentes de fosse, les systèmes de soutènement souterrain et les installations de stockage des résidus.", category: "Ingénierie" },
  { term: "Salle des Lingots (Gold Room)", short: "Zone sécurisée des métaux précieux", definition: "Une salle sécurisée à accès restreint dans une usine de traitement d'or où l'or est récupéré du charbon chargé, fondu en barres de doré et stocké avant transport. L'accès est strictement contrôlé.", category: "Traitement" },
  { term: "Teneur (Grade)", short: "Valeur de concentration minérale", definition: "La concentration d'un minéral ou métal précieux dans le minerai, typiquement exprimée en grammes par tonne (g/t) pour l'or ou en pourcentage (%) pour les métaux de base comme le cuivre et le zinc.", category: "Contrôle de Qualité" },
  { term: "Contrôle de Qualité du Minerai (Grade Control)", short: "Processus de gestion de la qualité", definition: "Le processus systématique de surveillance, d'échantillonnage et de gestion de la qualité et de la quantité du minerai extrait pour s'assurer qu'il répond aux exigences de l'usine de traitement.", category: "Contrôle de Qualité" },
  { term: "Broyeur à Boulets (Grinding Mill)", short: "Réducteur de taille des particules de minerai", definition: "Un grand tambour rotatif contenant des boulets ou des barres en acier utilisé pour broyer le minerai en fines particules pour le traitement des minéraux. Inclut les broyeurs à boulets, à barres et SAG.", category: "Équipements Miniers" },
  { term: "Contrôle du Sol (Ground Control)", short: "Stabilisation de la masse rocheuse", definition: "Toutes les mesures prises pour maintenir la stabilité des excavations et prévenir l'effondrement, y compris le boulonnage de roche, le béton projeté, l'installation de grillage et la surveillance des mouvements du sol.", category: "Soutènement du Sol" },
  { term: "Soutènement (Ground Support)", short: "Système de renforcement rocheux", definition: "Systèmes installés pour renforcer et stabiliser la masse rocheuse autour des excavations minières. Comprend les boulons de roche, les câbles, le grillage métallique, le béton projeté et les cadres en bois.", category: "Soutènement du Sol" },

  // H
  { term: "Toit (Hangingwall)", short: "Roche au-dessus du corps minéralisé", definition: "La masse rocheuse se trouvant au-dessus d'un corps minéralisé ou d'un filon incliné. Dans l'exploitation souterraine, le toit forme le plafond d'un chantier. Les ruptures de toit sont une cause majeure de blessures souterraines.", category: "Géologie" },
  { term: "Exploitation en Roche Dure", short: "Exploitation en roche solide", definition: "Exploitation minière impliquant l'extraction de métaux et de minéraux de formations rocheuses consolidées et solides en utilisant le forage, le dynamitage et l'excavation. Contrastée avec l'exploitation de roche tendre ou de placers.", category: "Méthodes d'Exploitation" },
  { term: "Route de Transport (Haul Road)", short: "Route pour véhicules miniers", definition: "Une route dans la mine conçue et entretenue pour les engins lourds et les camions de transport. Doit être correctement nivelée, drainée, arrosée pour la suppression de poussière et avoir des bermes adéquates.", category: "Infrastructure" },
  { term: "Camion de Transport (Haul Truck)", short: "Grand véhicule de transport du minerai", definition: "Un grand camion hors-route utilisé pour transporter le minerai et les stériles entre la fosse ou les travaux souterrains et l'usine de traitement ou la décharge. Les capacités varient de 40 à plus de 400 tonnes.", category: "Équipements Miniers" },
  { term: "Danger (Hazard)", short: "Source potentielle de préjudice", definition: "Toute condition, situation, substance ou pratique ayant le potentiel de causer un préjudice, une blessure, une maladie ou un décès à une personne, ou des dommages aux biens ou à l'environnement.", category: "Sécurité Minière" },
  { term: "Identification des Dangers", short: "Repérage des dangers au travail", definition: "Le processus systématique d'identification de tous les dangers potentiels avant de commencer le travail, généralement capturé dans une JSA ou une évaluation des risques. La première étape la plus critique dans le processus de gestion des risques.", category: "Sécurité Minière" },
  { term: "Matières Dangereuses (HazMat)", short: "Matières dangereuses", definition: "Matières dangereuses — substances inflammables, explosives, corrosives, oxydantes, toxiques ou autrement dangereuses. La manipulation nécessite une formation spéciale, un EPI approprié et le respect des Fiches de Données de Sécurité.", category: "Sécurité Minière" },
  { term: "Chevalement (Headframe)", short: "Structure de support du puits de surface", definition: "La structure en acier ou en béton érigée au-dessus d'un puits de mine pour soutenir l'équipement de levage et guider les câbles. Le chevalement est le symbole le plus reconnaissable d'une mine souterraine.", category: "Structures Minières" },
  { term: "Paroi Haute (High Wall)", short: "Front vertical exposé de fosse", definition: "Le front de roche non excavé restant après le retrait du mort-terrain dans l'exploitation à ciel ouvert. Les parois hautes peuvent atteindre des centaines de mètres et doivent être surveillées en permanence.", category: "Mine à Ciel Ouvert" },
  { term: "Hissage (Hoisting)", short: "Système de transport vertical en puits", definition: "Le système d'équipements comprenant le treuil, le chevalement, le puits et les convoyeurs utilisé pour déplacer verticalement le personnel, le minerai et les matériaux dans un puits de mine.", category: "Équipements Miniers" },
  { term: "Exploitation Hydraulique", short: "Excavation à jet d'eau haute pression", definition: "Une technique minière utilisant des jets d'eau à haute pression pour déloger et transporter le minerai ou le mort-terrain. Couramment utilisée dans l'orpaillage alluvionnaire et certaines opérations de surface.", category: "Méthodes d'Exploitation" },
  { term: "Pression Hydrostatique", short: "Pression de l'eau souterraine", definition: "La pression exercée par une colonne d'eau souterraine. Une pression hydrostatique élevée peut déstabiliser les parois de fosse, forcer l'eau dans les excavations et causer des irruptions soudaines.", category: "Sécurité Minière" },

  // I
  { term: "Inclinomètre", short: "Dispositif de surveillance d'inclinaison", definition: "Un instrument installé dans un sondage pour mesurer l'angle d'inclinaison d'une pente ou d'une structure au fil du temps, utilisé pour détecter et surveiller l'instabilité potentielle des parois de fosse.", category: "Surveillance" },
  { term: "Formation à l'Accueil (Induction Training)", short: "Formation de sécurité pour nouveaux travailleurs", definition: "Formation de sécurité obligatoire fournie à tous les nouveaux travailleurs, sous-traitants et visiteurs avant d'entrer sur un site minier. Couvre les règles du site, les procédures d'urgence, la sensibilisation aux dangers et les exigences EPI.", category: "Sécurité Minière" },
  { term: "Capteur Infrarouge", short: "Dispositif de détection chaleur/mouvement", definition: "Un capteur qui détecte la chaleur ou le mouvement, utilisé sur les sites miniers pour la détection d'incendie, les systèmes d'avertissement de proximité sur les engins lourds et la détection d'intrusion.", category: "Surveillance" },
  { term: "Irruption (Inrush)", short: "Inondation soudaine d'eau ou matériaux", definition: "Une entrée soudaine et incontrôlée d'eau, de boue ou d'autres matériaux dans une excavation minière. Les irruptions peuvent être catastrophiques et sont typiquement causées par la violation de réservoirs d'eau souterrains.", category: "Dangers du Sol" },
  { term: "Inspecteur", short: "Régulateur de sécurité minière", definition: "Un fonctionnaire nommé par le gouvernement ayant l'autorité d'entrer et d'inspecter les sites miniers pour assurer la conformité aux réglementations minières, aux normes de sécurité et aux exigences environnementales.", category: "Sécurité et Personnel" },
  { term: "Roche Intrusive", short: "Masse rocheuse solidifiée du magma", definition: "Roche formée à partir de magma qui s'est introduit dans des formations existantes et s'est solidifié sous terre. Les corps intrusifs comme le granite et la diorite sont des hôtes communs pour de nombreux gisements de minerai métallique.", category: "Géologie" },

  // J
  { term: "JST (Analyse de Sécurité au Travail)", short: "Analyse de Sécurité au Travail", definition: "Analyse de Sécurité au Travail — un processus systématique pour identifier les dangers associés à un travail ou une tâche spécifique avant le début du travail, puis déterminer les contrôles appropriés pour éliminer ou minimiser les risques pour les travailleurs. Obligatoire avant toutes les tâches à risque élevé.", category: "Planification Sécurité" },
  { term: "Foreuse Jumbo", short: "Foreuse souterraine multi-bras", definition: "Une machine de forage souterraine automotrice avec un ou plusieurs bras de forage utilisée pour forer des trous de mine dans les fronts de tunnels. L'outil de développement principal dans les mines souterraines.", category: "Équipements Miniers" },

  // K
  { term: "Interrupteur d'Urgence (Kill Switch)", short: "Commande d'arrêt d'urgence", definition: "Un dispositif d'urgence qui coupe immédiatement l'alimentation d'une machine ou d'un convoyeur lorsqu'il est activé. Doit être clairement marqué, facilement accessible et régulièrement testé.", category: "Sécurité Minière" },
  { term: "Four Rotatif (Kiln)", short: "Traitement du minerai à haute température", definition: "Un four rotatif utilisé pour chauffer le minerai ou le concentré à des températures élevées pour chasser l'humidité, oxyder les sulfures ou préparer le matériau pour la fonte. Un équipement clé dans de nombreuses opérations métallurgiques.", category: "Traitement" },

  // L
  { term: "Lixiviation (Leaching)", short: "Extraction chimique de minéraux", definition: "Le processus de dissolution de minéraux précieux du minerai à l'aide de solutions chimiques (typiquement du cyanure pour l'or ou de l'acide sulfurique pour le cuivre). Peut être réalisé en tas, en cuves ou in situ.", category: "Traitement" },
  { term: "Lithologie", short: "Classification du type de roche", definition: "Les caractéristiques physiques d'une roche, notamment sa couleur, sa texture, sa composition minéralogique et la taille de ses grains. L'enregistrement lithologique précis des carottes de forage est essentiel pour l'interprétation géologique.", category: "Géologie" },
  { term: "Chargement et Transport (Load and Haul)", short: "Excavation et transport du minerai", definition: "Les opérations combinées de chargement du minerai concassé ou des stériles dans des camions à l'aide d'excavatrices ou de chargeuses, et leur transport vers l'usine de traitement, la décharge ou le stock.", category: "Opérations" },
  { term: "Chargeuse (Loader)", short: "Machine de chargement à l'avant", definition: "Une machine sur roues ou chenilles avec un godet avant utilisée pour charger les matériaux concassés dans les camions de transport. Également appelée chargeuse à roues.", category: "Équipements Miniers" },
  { term: "Filon Métallifère (Lode)", short: "Veine rocheuse minéralisée", definition: "Un filon ou une veine de minerai métallique enchâssée dans la roche. L'exploitation de filons implique l'extraction du minerai de ces veines, contrairement à l'exploitation alluvionnaire.", category: "Géologie" },
  { term: "Cadenassage/Étiquetage (LOTO)", short: "Procédure de verrouillage/étiquetage", definition: "Cadenassage/Étiquetage — une procédure de sécurité critique garantissant que les sources d'énergie dangereuses (électriques, hydrauliques, pneumatiques) sont isolées et ne peuvent pas être ré-énergisées pendant les travaux de maintenance. L'absence de LOTO est une cause fréquente de blessures graves.", category: "Sécurité Minière" },

  // M
  { term: "Dépôt d'Explosifs (Magazine)", short: "Installation de stockage d'explosifs", definition: "Une installation de stockage sécurisée et spécialement conçue pour les explosifs, détonateurs et accessoires de tir. Doit être agréée, entretenue selon des normes strictes et située à une distance de sécurité des installations.", category: "Forage et Dynamitage" },
  { term: "Voie d'Accès (Manway)", short: "Passage d'accès pour travailleurs souterrains", definition: "Un passage ou escalier dans une mine souterraine utilisé exclusivement par les travailleurs pour l'accès et la sortie. Les voies d'accès doivent être maintenues dégagées de tout obstacle et en bon état de sécurité.", category: "Structures Minières" },
  { term: "Méthane", short: "Gaz souterrain explosif", definition: "Un gaz inflammable et explosif (CH4) présent naturellement dans les mines de charbon et certaines mines métallifères. Les accumulations de méthane doivent être détectées tôt et diluées par ventilation pour prévenir les explosions.", category: "Dangers du Sol" },
  { term: "Usine de Traitement (Mill)", short: "Installation de traitement du minerai", definition: "Une installation où le minerai concassé est broyé et traité pour extraire les minéraux précieux. Fait également référence aux machines de broyage (broyeurs à boulets, à barres) au sein de l'installation.", category: "Traitement" },
  { term: "Plan de Mine", short: "Plan opérationnel de l'exploitation minière", definition: "Un document complet spécifiant comment une mine sera exploitée, incluant la conception de la fosse ou des travaux souterrains, le calendrier de production, les besoins en équipements et les stratégies de gestion des déchets.", category: "Opérations" },
  { term: "Sauvetage Minier (Mine Rescue)", short: "Équipe d'urgence souterraine", definition: "Une équipe de personnel spécialement formé et équipé pour répondre aux urgences souterraines incluant les incendies, les explosions, les éboulements et les inondations. Toutes les mines doivent avoir accès à une équipe de sauvetage.", category: "Procédures d'Urgence" },
  { term: "Tir Raté (Misfired Shot)", short: "Détonation explosive ratée", definition: "Une charge explosive qui n'a pas détoné comme prévu lors d'un tir. Les tirs ratés sont extrêmement dangereux et ne doivent être investigués et traités que par un artificier sous licence.", category: "Forage et Dynamitage" },
  { term: "Surveillance (Monitoring)", short: "Mesure de sécurité en cours", definition: "La mesure et l'enregistrement continus ou périodiques de paramètres critiques pour la sécurité tels que le mouvement des pentes, les niveaux de gaz, la pression d'eau et l'intégrité structurelle.", category: "Sécurité Minière" },
  { term: "Niveleuse (Motor Grader)", short: "Machine de nivelage des routes", definition: "Une machine avec une longue lame réglable utilisée pour créer des surfaces planes et entretenir les routes de transport sur les sites miniers. Un bon nivellement des routes réduit les accidents de véhicules.", category: "Équipements Miniers" },
  { term: "Déblayage (Mucking)", short: "Chargement de la roche concassée", definition: "Le processus de chargement de la roche concassée ou brisée (muck) dans des camions ou autres convoyeurs pour le transport. Le terme est couramment utilisé dans les opérations d'exploitation souterraine.", category: "Opérations" },
  { term: "Point de Rassemblement (Muster Point)", short: "Lieu d'assemblage d'urgence", definition: "Un emplacement sûr, pré-désigné, où tout le personnel doit se rassembler en cas d'évacuation d'urgence. Doit être clairement marqué, bien connu de tout le personnel du site et pratiqué régulièrement.", category: "Procédures d'Urgence" },

  // N
  { term: "Incident Évité (Near Miss)", short: "Quasi-accident de sécurité", definition: "Un événement non planifié qui n'a pas entraîné de blessure, maladie ou dommage — mais aurait pu le faire. Les incidents évités doivent être signalés et investigués immédiatement pour prévenir de futurs accidents.", category: "Sécurité Minière" },
  { term: "Surdité Professionnelle (NIHL)", short: "Surdité due au bruit de travail", definition: "Dommages auditifs permanents causés par une exposition prolongée à des niveaux de bruit élevés en milieu de travail. L'exploitation minière est l'une des industries à risque le plus élevé pour la surdité professionnelle.", category: "Santé et Hygiène" },

  // O
  { term: "Mine à Ciel Ouvert (Open Pit)", short: "Mine d'excavation de surface", definition: "Un type de mine à ciel ouvert dont la roche ou les minéraux sont extraits d'une fosse ouverte. Les mines à ciel ouvert sont caractérisées par une série de gradins descendants et conviennent aux grands corps minéralisés proches de la surface.", category: "Méthodes d'Exploitation" },
  { term: "Minerai (Ore)", short: "Roche économiquement précieuse", definition: "Roche ou minéral contenant suffisamment d'une substance de valeur (métal, minéral ou gemme) pour rendre économiquement rentable son extraction et son traitement au prix du marché actuel.", category: "Géologie" },
  { term: "Corps Minéralisé (Ore Body)", short: "Concentration de gisement minéral", definition: "Une masse de roche contenant une teneur en minéraux suffisante et une étendue suffisante pour être économiquement exploitable. Les corps minéralisés peuvent être tabulaires (plats), massifs ou disséminés.", category: "Géologie" },
  { term: "Cheminée à Minerai (Ore Pass)", short: "Puits de chute de minerai souterrain", definition: "Une ouverture souterraine verticale ou très inclinée à travers laquelle le minerai est laissé tomber d'un niveau supérieur vers un niveau inférieur pour la collecte et le transport.", category: "Structures Minières" },
  { term: "Réserve de Minerai (Ore Reserve)", short: "Estimation de la quantité de minerai exploitable", definition: "La portion d'une ressource minérale qui a été évaluée comme économiquement et techniquement exploitable dans des conditions définies. Utilisée pour déterminer la durée de vie de la mine et la valeur financière.", category: "Opérations" },
  { term: "Mort-Terrain (Overburden)", short: "Stériles de surface au-dessus du minerai", definition: "Roche, sol et autres matériaux surmontant un gisement minéral qui doivent être retirés lors de l'exploitation à ciel ouvert avant d'accéder au minerai. Le mort-terrain est éliminé dans des décharges de stériles.", category: "Mine à Ciel Ouvert" },
  { term: "Oxydation", short: "Altération chimique des minéraux", definition: "Un processus chimique où les minéraux réagissent avec l'oxygène, changeant souvent leurs propriétés. Le minerai oxydé proche de la surface peut être plus facile à traiter que le minerai sulfuré frais plus profond.", category: "Géologie" },

  // P
  { term: "Pâte de Remblayage (Paste Fill)", short: "Remblai de résidus cimentés", definition: "Un mélange épais de résidus, d'eau et de liant (ciment) utilisé pour remplir les vides souterrains. Le remblai en pâte fournit un soutien structurel et réduit le volume de résidus nécessitant un stockage en surface.", category: "Soutènement du Sol" },
  { term: "Permis de Travail", short: "Autorisation formelle de travail", definition: "Une autorisation écrite formelle requise avant de commencer des travaux à risque élevé tels que l'entrée en espace confiné, les travaux par points chauds, les travaux en hauteur ou l'isolation électrique.", category: "Sécurité Minière" },
  { term: "Pilier (Pillar)", short: "Bloc de soutien rocheux non exploité", definition: "Un bloc de minerai ou de roche non exploité laissé en place pour soutenir le toit et les parois des excavations souterraines. Les piliers doivent être dimensionnés correctement — l'extraction prématurée des piliers peut causer des effondrements catastrophiques.", category: "Soutènement du Sol" },
  { term: "Assèchement de la Fosse (Pit Dewatering)", short: "Élimination de l'eau de la fosse", definition: "Le processus continu d'élimination des eaux souterraines et de surface d'une mine à ciel ouvert pour maintenir des conditions de travail sûres et praticables. Comprend les pompes, puisards, drains et canaux de dérivation.", category: "Opérations" },
  { term: "Limite de Fosse (Pit Limit)", short: "Limite économique de la fosse", definition: "La limite d'une mine à ciel ouvert, définie par le point où le coût de l'exploitation dépasse les revenus du minerai. Les limites de fosse sont calculées par des logiciels d'optimisation.", category: "Mine à Ciel Ouvert" },
  { term: "Exploitation Alluviale (Placer Mining)", short: "Extraction de dépôts alluviaux", definition: "L'extraction de minéraux précieux (typiquement l'or, l'étain ou les diamants) de dépôts alluviaux dans les lits de rivières, les plages ou les anciens chenaux d'eau en utilisant le lavage et la séparation par gravité.", category: "Méthodes d'Exploitation" },
  { term: "Portail (Portal)", short: "Entrée de tunnel de mine", definition: "L'entrée d'une ouverture de mine souterraine horizontale ou inclinée. Les portails doivent être sécurisés avec des murs en béton pour prévenir l'effondrement et clairement marqués avec des panneaux de sécurité.", category: "Structures Minières" },
  { term: "EPI (Équipement de Protection Individuelle)", short: "Équipement de Protection Individuelle", definition: "Équipement de Protection Individuelle — tout dispositif, vêtement ou équipement porté par un travailleur pour minimiser l'exposition à des dangers professionnels spécifiques. L'EPI obligatoire dans les mines comprend le casque, les bottes de sécurité, le gilet haute visibilité, les lunettes et les gants.", category: "Sécurité Minière" },
  { term: "Inspection Avant Poste", short: "Vérification de sécurité de l'équipement", definition: "Une inspection obligatoire de l'équipement et de la zone de travail effectuée par l'opérateur avant de commencer chaque poste. Identifie les défauts, dangers et conditions dangereuses avant le début du travail.", category: "Sécurité Minière" },
  { term: "Amorçage (Priming)", short: "Mise en place de l'initiation explosive", definition: "Le processus d'insertion d'un détonateur dans un explosif amorceur pour créer un assemblage d'initiation qui déclenchera de manière fiable la charge explosive principale dans un trou de mine.", category: "Forage et Dynamitage" },
  { term: "Système de Détection de Proximité", short: "Alerte de collision véhicule-travailleur", definition: "Un système électronique qui détecte et alerte lorsqu'une personne entre dans la zone de danger autour d'engins lourds en opération, aidant à prévenir les collisions véhicule-piéton — une cause majeure de décès dans les mines.", category: "Sécurité Minière" },
  { term: "Minerai Pyriteux", short: "Type de minerai sulfuré", definition: "Minerai contenant des quantités significatives de sulfure de fer (pyrite, FeS2). Les minerais pyriteux peuvent générer un drainage minier acide lorsqu'ils sont exposés à l'air et à l'eau.", category: "Géologie" },

  // Q
  { term: "Carrière (Quarry)", short: "Site d'extraction de roche de surface", definition: "Un type de mine à ciel ouvert d'où sont extraits des matériaux de construction tels que le calcaire, le granit, le sable et le gravier. Les carrières utilisent le forage et le dynamitage similaires aux mines métallifères.", category: "Méthodes d'Exploitation" },
  { term: "Quartzite", short: "Roche métamorphique dure", definition: "Une roche métamorphique dure formée à partir de grès. Le quartzite est extrêmement abrasif et présente un risque significatif de silicose lors du forage ou du dynamitage, nécessitant une protection respiratoire et la suppression des poussières.", category: "Géologie" },

  // R
  { term: "Montage (Raise)", short: "Galerie verticale ou inclinée ascendante", definition: "Une ouverture souterraine verticale ou fortement inclinée creusée vers le haut d'un niveau à un autre. Les montages sont utilisés pour la ventilation, les cheminées à minerai et l'accès entre les niveaux.", category: "Structures Minières" },
  { term: "Réhabilitation (Reclamation)", short: "Restauration du site minier", definition: "Le processus de restauration d'une zone minée à un état stable, sûr et productif après la cessation des opérations minières. Comprend le remodelage, la revégétalisation, la gestion de l'eau et la surveillance continue.", category: "Environnement" },
  { term: "Ressource (Resource)", short: "Estimation de la quantité du gisement", definition: "Une estimation de la quantité et de la qualité de la minéralisation dans un gisement, classée en catégories Inférée, Indiquée et Mesurée selon le niveau de confiance géologique.", category: "Exploration" },
  { term: "Éponte (Rib)", short: "Paroi latérale souterraine", definition: "La paroi latérale d'une excavation souterraine telle qu'une galerie ou un tunnel. Les épontes sont soumises à la pression du sol et doivent être écaillées et soutenues pour prévenir les chutes de roches.", category: "Structures Minières" },
  { term: "Risque (Risk)", short: "Probabilité × conséquence du préjudice", definition: "La combinaison de la probabilité qu'un danger cause un préjudice et de la gravité de ce préjudice. Risque = Probabilité × Conséquence. La gestion des risques consiste à réduire l'un ou les deux facteurs.", category: "Sécurité Minière" },
  { term: "Évaluation des Risques", short: "Évaluation formelle des dangers", definition: "Le processus systématique d'identification des dangers, d'évaluation de la probabilité et des conséquences de préjudice, et de détermination des mesures de contrôle appropriées pour réduire le risque à un niveau acceptable.", category: "Planification Sécurité" },
  { term: "Boulon de Roche (Rock Bolt)", short: "Boulon de renforcement du sol", definition: "Un boulon en acier installé dans des trous forés dans la roche pour renforcer et stabiliser la masse rocheuse environnante. Les boulons de roche sont la forme de soutènement du sol la plus utilisée dans l'exploitation souterraine.", category: "Soutènement du Sol" },
  { term: "Coup de Toit (Rock Burst)", short: "Éjection violente soudaine de roche", definition: "Une rupture soudaine et violente de roche dans un environnement souterrain fortement contraint, causant l'éjection explosive de roche des parois ou du toit. Un danger majeur dans les mines souterraines profondes.", category: "Dangers du Sol" },
  { term: "Mécanique des Roches (Rock Mechanics)", short: "Comportement des roches sous contrainte", definition: "La science du comportement de la roche sous des charges et des contraintes appliquées. Les principes de la mécanique des roches sous-tendent la conception de toutes les excavations souterraines, pentes de fosse et systèmes de soutènement.", category: "Ingénierie" },
  { term: "ROM (Minerai Brut)", short: "Minerai tel qu'extrait de la mine", definition: "Tout-venant de Mine — minerai tel qu'il sort directement du front de taille, avant tout traitement ou tri. Le matériau ROM est transporté vers un stock ou directement vers le concasseur de l'usine de traitement.", category: "Contrôle de Qualité" },
  { term: "Boulon de Toit (Roof Bolt)", short: "Support de plafond souterrain", definition: "Un boulon de roche installé dans le toit (voûte) d'une excavation souterraine pour lier et stabiliser les couches de roche en hauteur. Le boulonnage de toit est essentiel dans toutes les mines souterraines.", category: "Soutènement du Sol" },

  // S
  { term: "Fiche de Données de Sécurité (FDS)", short: "Document de danger chimique", definition: "Un document standardisé fournissant des informations détaillées sur une substance dangereuse, notamment ses dangers physiques et sanitaires, sa manipulation sûre, son stockage, son élimination et les procédures d'urgence.", category: "Sécurité Minière" },
  { term: "Responsable Sécurité (Safety Officer)", short: "Gestionnaire de sécurité du site", definition: "Un professionnel formé responsable du développement, de la mise en œuvre et du suivi des systèmes de sécurité sur un site minier. Le responsable sécurité a l'autorité d'arrêter les travaux dangereux.", category: "Sécurité et Personnel" },
  { term: "Écaillage (Scaling)", short: "Élimination de la roche lâche", definition: "L'élimination manuelle ou mécanique de la roche lâche, fissurée ou instable des fronts de taille, parois et plafonds des mines avant le début des travaux dans cette zone. Réalisé à l'aide d'une barre d'écaillage ou d'un écailleur mécanique.", category: "Soutènement du Sol" },
  { term: "Surveillance Sismique", short: "Mesure des vibrations du sol", definition: "La mesure continue des vibrations du sol à l'aide de sismographes pour détecter et surveiller les mouvements rocheux souterrains, les effets du dynamitage et l'instabilité potentielle des pentes ou l'activité de coups de toit.", category: "Surveillance" },
  { term: "Puits (Shaft)", short: "Ouverture d'accès verticale de mine", definition: "Une ouverture souterraine verticale ou quasi-verticale utilisée pour l'accès, la ventilation, le levage du minerai et les services dans une mine souterraine. Les puits peuvent atteindre des profondeurs de plusieurs kilomètres dans les mines profondes.", category: "Structures Minières" },
  { term: "Béton Projeté (Shotcrete)", short: "Revêtement en béton pulvérisé", definition: "Béton pulvérisé à haute pression sur des surfaces rocheuses pour fournir un soutien structurel et prévenir la détérioration des parois et des toits des excavations. Largement utilisé dans le développement et la réhabilitation souterrains.", category: "Soutènement du Sol" },
  { term: "Artificier (Shot-Firer)", short: "Opérateur d'explosifs agréé", definition: "Une personne titulaire d'une licence pour manipuler, préparer et faire détoner des explosifs sur un site minier. Les artificiers sont responsables de l'exécution sûre de toutes les opérations de dynamitage et de la gestion des tirs ratés.", category: "Sécurité et Personnel" },
  { term: "Silice", short: "Poussière causant une maladie pulmonaire", definition: "Dioxyde de silicium (SiO2) — un minéral présent dans la plupart des types de roche. L'inhalation de poussière de silice fine provoque la silicose, une maladie pulmonaire grave, irréversible et potentiellement mortelle.", category: "Santé et Hygiène" },
  { term: "Silicose", short: "Maladie pulmonaire due à la poussière de silice", definition: "Une maladie pulmonaire professionnelle progressive, incurable et potentiellement mortelle causée par l'inhalation de poussière de silice cristalline fine au fil du temps. La prévention nécessite le contrôle des poussières, l'EPI respiratoire et un suivi régulier de la santé.", category: "Santé et Hygiène" },
  { term: "Pilier de Toit (Sill Pillar)", short: "Support horizontal de niveau de minerai", definition: "Un pilier horizontal de minerai non exploité laissé entre les niveaux d'abattage pour fournir un soutien de toit pour les travaux inférieurs. La récupération du pilier de toit est l'une des activités à risque le plus élevé dans l'exploitation souterraine.", category: "Soutènement du Sol" },
  { term: "Skip (Benne de Hissage)", short: "Godet de hissage de minerai en puits", definition: "Un grand seau ou conteneur utilisé pour hisser le minerai et les stériles de sous-terre vers la surface dans un puits de mine. Les skips sont contrebalancés et guidés par la structure du puits.", category: "Équipements Miniers" },
  { term: "Surveillance des Pentes (Slope Monitoring)", short: "Suivi des mouvements de paroi", definition: "La mesure continue du mouvement des parois de fosse et des faces de décharge pour détecter les premiers signes d'instabilité. Les méthodes incluent les prismes de levé, le radar, les inclinomètres et les systèmes GPS.", category: "Surveillance" },
  { term: "Stabilité des Pentes (Slope Stability)", short: "Condition de sécurité de la paroi de fosse", definition: "La capacité d'une paroi de fosse, d'une excavation souterraine ou d'une face de décharge de stériles à rester en place sans rupture. Dépend de la résistance de la roche, de la structure géologique, de l'angle de pente, de la pression d'eau et des effets du dynamitage.", category: "Géotechnique" },
  { term: "Boue (Slurry)", short: "Mélange d'eau et de solides", definition: "Un mélange semi-fluide de particules solides finement broyées et d'eau, couramment trouvé dans les circuits de traitement des minéraux. Les pipelines de boue transportent le minerai traité entre les installations.", category: "Traitement" },
  { term: "Fonte (Smelting)", short: "Extraction de métal par chaleur intense", definition: "Le processus d'extraction du métal du minerai en le chauffant à des températures élevées dans un four, provoquant la réduction chimique et la séparation du métal des impuretés (scories).", category: "Traitement" },
  { term: "Résidu d'Excavation (Spoil)", short: "Matériau de déblai excavé", definition: "Mort-terrain, stériles ou autres matériaux retirés pendant l'exploitation minière qui n'ont aucune valeur économique. Le résidu doit être éliminé dans des décharges de stériles désignées conçues pour une stabilité à long terme.", category: "Gestion des Déchets" },
  { term: "Combustion Spontanée", short: "Matériau qui s'enflamme spontanément", definition: "L'auto-ignition du charbon ou des stériles contenant des sulfures lorsqu'exposés à l'air sans source d'ignition externe. Les incendies de combustion spontanée dans les décharges et les mines de charbon sont difficiles à éteindre.", category: "Dangers du Sol" },
  { term: "Bourrage (Stemming)", short: "Matériau de remplissage du haut du trou de mine", definition: "Matériau inerte (généralement des déblais de forage ou de la roche concassée) placé dans la partie supérieure d'un trou de mine au-dessus de la charge explosive pour contenir l'énergie du tir et réduire les projections.", category: "Forage et Dynamitage" },
  { term: "Stock de Minerai (Stockpile)", short: "Tas de stockage de minerai ou stériles", definition: "Une zone désignée où le minerai, les stériles ou le matériau à faible teneur est temporairement stocké avant le traitement, le traitement ou l'élimination permanente. La gestion des stocks comprend le suivi de la qualité et la surveillance de la stabilité.", category: "Opérations" },
  { term: "Chantier (Stope)", short: "Excavation de minerai souterrain", definition: "L'excavation souterraine d'où le minerai est extrait après le développement. Les chantiers sont les principales zones de production dans une mine souterraine et nécessitent une conception soigneuse du soutènement.", category: "Structures Minières" },
  { term: "Direction (Strike)", short: "Direction horizontale du corps minéralisé", definition: "La direction horizontale d'une couche rocheuse, d'une faille ou d'un corps minéralisé, mesurée par rapport au nord. Comprendre la direction d'un corps minéralisé est fondamental pour la planification minière.", category: "Géologie" },
  { term: "Rapport de Découverture (Strip Ratio)", short: "Ratio d'enlèvement stérile/minerai", definition: "Le rapport du matériau de déblai (mort-terrain) au minerai qui doit être extrait. Un rapport de découverture de 5:1 signifie que 5 tonnes de stériles sont déplacées pour chaque tonne de minerai.", category: "Mine à Ciel Ouvert" },
  { term: "Foudroyage par Sous-Niveaux (Sub-Level Caving)", short: "Méthode de foudroyage souterraine", definition: "Une méthode d'exploitation souterraine où le minerai est foré et dynamité à partir de sous-niveaux et laissé s'effondrer et s'écouler vers des points de soutirage en dessous.", category: "Méthodes d'Exploitation" },
  { term: "Affaissement (Subsidence)", short: "Enfoncement de la surface du sol", definition: "L'enfoncement ou le tassement de la surface terrestre au-dessus d'une mine souterraine causé par l'effondrement ou la fermeture de vides souterrains. L'affaissement de surface peut endommager les infrastructures et les routes.", category: "Dangers du Sol" },
  { term: "Puisard (Sump)", short: "Fosse de collecte d'eau souterraine", definition: "Une fosse ou un point bas dans une mine souterraine où l'eau se collecte pour être pompée vers la surface. Les puisards doivent être entretenus et pompés régulièrement pour prévenir l'inondation des zones de travail.", category: "Structures Minières" },
  { term: "Caution Environnementale (Surety Bond)", short: "Garantie financière environnementale", definition: "Une caution financière déposée par une compagnie minière pour garantir qu'elle remplira ses obligations environnementales, notamment la réhabilitation et la fermeture, lorsque les opérations minières cesseront.", category: "Environnement" },

  // T
  { term: "Résidus (Tailings)", short: "Matériaux de déchets de traitement", definition: "Roche finement broyée et déchets de traitement restant après l'extraction des minéraux précieux du minerai. Les résidus contiennent des produits chimiques résiduels et doivent être stockés dans des Installations de Stockage des Résidus (ISR).", category: "Gestion des Déchets" },
  { term: "Installation de Stockage des Résidus (ISR)", short: "Barrage ou stockage de résidus", definition: "Une structure conçue pour contenir les résidus du traitement des minéraux. Les ruptures d'ISR peuvent être catastrophiques — causant des pertes humaines et de graves dommages environnementaux. Nécessite une surveillance constante et une gestion experte.", category: "Gestion des Déchets" },
  { term: "Machine Tunnelière (TBM)", short: "Machine de forage de tunnels", definition: "Machine Tunnelière — un grand dispositif mécanique utilisé pour creuser des tunnels en broyant la roche avec une tête de coupe rotative. Les TBM produisent des tunnels plus lisses avec moins de perturbation du sol que les méthodes de forage et dynamitage.", category: "Équipements Miniers" },
  { term: "Tonne", short: "Unité métrique de poids (1000 kg)", definition: "L'unité de masse standard utilisée dans l'exploitation minière, égale à 1 000 kilogrammes (2 205 livres). Les teneurs en minerai sont typiquement exprimées en grammes par tonne (g/t) et la production en tonnes par jour (t/j) ou par an (t/a).", category: "Opérations" },
  { term: "Réunion de Sécurité (Toolbox Talk)", short: "Briefing de sécurité avant le poste", definition: "Une courte réunion de sécurité informelle tenue avant un poste de travail ou une tâche spécifique pour discuter des dangers, des procédures de sécurité et du plan de travail. La présence est obligatoire pour tous les travailleurs.", category: "Planification Sécurité" },
  { term: "Topographie", short: "Carte de la forme du terrain en surface", definition: "La forme naturelle et les caractéristiques du terrain, notamment les collines, les vallées et les réseaux de drainage. Les cartes topographiques et les relevés sont essentiels pour la conception de la mine et la planification des routes de transport.", category: "Ingénierie" },
  { term: "Métal Parasite (Tramp Metal)", short: "Métal indésirable dans le minerai", definition: "Morceaux de métal tels que des aciers de forage brisés, des dents de godet et des fragments de câble qui se retrouvent dans le flux de minerai et peuvent endommager les équipements de concassage et de broyage.", category: "Opérations" },
  { term: "Tunnel", short: "Passage horizontal souterrain", definition: "Un passage souterrain horizontal reliant deux ouvertures en surface. Les tunnels sont creusés pour l'accès, l'exploration et le transport dans les opérations minières à ciel ouvert et souterraines.", category: "Structures Minières" },

  // U
  { term: "Exploitation Souterraine (Underground Mining)", short: "Extraction de minerai en sous-surface", definition: "Exploitation minière conduite sous la surface de la terre, accessible via des puits, des descenderies ou des adits. Utilisée lorsque les corps minéralisés sont trop profonds pour l'exploitation à ciel ouvert. Pose des dangers uniques incluant les chutes de roches, les incendies et la mauvaise ventilation.", category: "Méthodes d'Exploitation" },
  { term: "Résistance à la Compression Uniaxiale (RCU)", short: "Mesure de la résistance de la roche", definition: "Une mesure en laboratoire de la contrainte maximale qu'un échantillon cylindrique de roche peut supporter sous une charge axiale avant rupture. La RCU est une entrée fondamentale pour la conception du soutènement souterrain et l'analyse de stabilité des pentes.", category: "Ingénierie" },
  { term: "Puits d'Extraction d'Air (Upcast Shaft)", short: "Puits d'échappement de ventilation de mine", definition: "Un puits de mine à travers lequel l'air contaminé et chauffé est aspiré hors des travaux souterrains par des ventilateurs. Le puits d'extraction d'air est un élément critique du système de ventilation de la mine.", category: "Ventilation" },

  // V
  { term: "Ventilation", short: "Circulation d'air souterraine", definition: "Le système de ventilateurs, puits, montages et conduites utilisé pour fournir de l'air frais aux travaux souterrains et éliminer l'air contaminé, la chaleur, la poussière et les fumées de dynamitage. Une ventilation inadéquate est l'un des dangers souterrains les plus graves.", category: "Ventilation" },
  { term: "Vide (Void)", short: "Espace vide souterrain", definition: "Un espace souterrain vide créé par l'exploitation minière. Les vides doivent être correctement soutenus, remblayés ou clôturés pour prévenir l'effondrement, l'affaissement de surface ou l'entrée accidentelle par des travailleurs.", category: "Dangers du Sol" },
  { term: "Rapport de Vides (Void Ratio)", short: "Rapport espace poral/solide", definition: "Le rapport du volume de vides (pores et espaces) au volume de matériau solide dans la roche ou le sol. Des rapports de vides élevés indiquent des conditions de sol plus lâches et potentiellement moins stables.", category: "Géotechnique" },

  // W
  { term: "Stériles (Waste Rock)", short: "Roche excavée non économique", definition: "Roche excavée pendant l'exploitation minière mais ne contenant pas suffisamment de teneur en minéraux pour être économiquement traitée. Les stériles sont éliminés de façon permanente dans des décharges de stériles conçues.", category: "Gestion des Déchets" },
  { term: "Nappe Phréatique (Water Table)", short: "Niveau d'eau souterraine", definition: "Le niveau sous la surface terrestre à partir duquel le sol est saturé d'eau. L'exploitation minière sous la nappe phréatique nécessite l'exhaure et peut affecter les réserves d'eau souterraine locales.", category: "Hydrologie" },
  { term: "Altération (Weathering)", short: "Détérioration de la surface rocheuse", definition: "La décomposition physique et chimique de la roche à la surface ou près de la surface terrestre par l'exposition aux intempéries, à l'eau et aux processus biologiques. La roche altérée est généralement plus faible et plus sujette à l'instabilité des pentes.", category: "Géologie" },
  { term: "Front de Taille (Working Face)", short: "Front d'excavation actif", definition: "La zone de la mine où l'excavation, le forage ou le dynamitage actif est en cours. Il s'agit généralement de la zone à risque le plus élevé sur un site minier nécessitant les contrôles de danger les plus stricts.", category: "Structures Minières" },
  { term: "Poste de Travail (Working Place)", short: "Zone de travail individuelle du mineur", definition: "L'emplacement spécifique où un mineur individuel ou une équipe travaille à tout moment donné. Chaque poste de travail doit être inspecté pour les dangers avant le début du travail au début de chaque poste.", category: "Sécurité Minière" },

  // X
  { term: "Analyseur XRF", short: "Scanner portable de teneur en minerai", definition: "Analyseur à Fluorescence X — un appareil portable de poche utilisé pour déterminer rapidement la composition élémentaire et la teneur de la roche ou des échantillons de minerai sur le terrain sans traitement en laboratoire.", category: "Tests et Analyses" },

  // Additional terms
  { term: "Boulon d'Ancrage (Anchor Bolt)", short: "Soutien rocheux d'ancrage", definition: "Un boulon en acier scellé ou ancré mécaniquement profondément dans la roche pour attacher les masses rocheuses instables et renforcer les parois de fosse ou les excavations souterraines contre les mouvements.", category: "Soutènement du Sol" },
  { term: "Équipement Autonome", short: "Machinerie minière auto-opérée", definition: "Équipement minier tel que les camions de transport et les foreuses qui opèrent sans conducteur humain, contrôlé par des ordinateurs embarqués et des systèmes de surveillance à distance. Réduit l'exposition des travailleurs aux zones dangereuses.", category: "Équipements Miniers" },
  { term: "Broyeur à Boulets (Ball Mill)", short: "Tambour rotatif de broyage de minerai", definition: "Un grand tambour en acier partiellement rempli de boulets en acier qui tourne pour broyer le minerai en fines particules pour le traitement des minéraux. L'un des équipements les plus énergivores d'une usine de traitement.", category: "Équipements Miniers" },
  { term: "Bentonite", short: "Argile scellante pour fluide de forage", definition: "Un minéral argileux hautement absorbant utilisé comme additif de fluide de forage pour sceller les parois des sondages, lubrifier les trépans et transporter les déblais de forage vers la surface lors du forage d'exploration.", category: "Exploration" },
  { term: "Enregistrement des Trous de Mine (Blasthole Logging)", short: "Échantillonnage de copeaux de minerai", definition: "L'échantillonnage systématique et l'enregistrement des copeaux de forage des trous de mine pour déterminer la teneur en minerai avant le dynamitage. L'enregistrement des trous de mine est un outil de contrôle de qualité critique.", category: "Contrôle de Qualité" },
  { term: "Câble de Soutènement (Cable Bolt)", short: "Soutien rocheux flexible long", definition: "Un câble en acier flexible scellé dans un long trou de forage pour renforcer et assembler de grands volumes de masse rocheuse, fournissant un soutien dans les zones à forte contrainte ou à géologie complexe.", category: "Soutènement du Sol" },
  { term: "Monoxyde de Carbone (CO)", short: "Gaz minier toxique inodore", definition: "Un gaz incolore, inodore et hautement toxique produit par la combustion incomplète de carburant et par le dynamitage. Le CO ne peut pas être détecté par l'odorat — les détecteurs de gaz sont essentiels dans tous les environnements souterrains.", category: "Sécurité Minière" },
  { term: "Bassin de Rétention (Catchment Pond)", short: "Fosse de collecte d'eau de surface", definition: "Un bassin conçu pour collecter et contenir les eaux de ruissellement des zones du site minier, empêchant les eaux contaminées de s'écouler dans les cours d'eau naturels.", category: "Environnement" },
  { term: "Tir Contrôlé (Controlled Blasting)", short: "Tir de précision pour protection des parois", definition: "Techniques de dynamitage telles que le prédécoupage et le tir de contour utilisées près des parois finales de fosse pour minimiser les dommages à la roche et produire une face de pente stable et propre.", category: "Forage et Dynamitage" },
  { term: "Convoyeur à Bande (Conveyor Belt)", short: "Système de transport continu de minerai", definition: "Un système de bande mobile continue utilisé pour transporter le minerai, la roche concassée ou les déchets sur de longues distances en surface ou sous terre. Doit être équipé d'arrêts d'urgence, de protections et de commutateurs d'alignement.", category: "Équipements Miniers" },
  { term: "Puits d'Injection d'Air (Downcast Shaft)", short: "Puits d'entrée d'air frais", definition: "Un puits de mine à travers lequel l'air frais est aspiré vers les travaux souterrains. Le puits d'injection d'air est le côté d'entrée du circuit de ventilation souterrain.", category: "Ventilation" },
  { term: "Point de Soutirage (Draw Point)", short: "Ouverture de collecte de minerai souterrain", definition: "L'ouverture à la base d'un chantier ou d'un bloc de foudroyage à travers laquelle le minerai brisé s'écoule par gravité pour le chargement et le transport. La gestion des points de soutirage est critique pour la récupération du minerai.", category: "Structures Minières" },
  { term: "Forage et Dynamitage (Drill and Blast)", short: "Méthode standard d'excavation rocheuse", definition: "La méthode la plus largement utilisée d'excavation rocheuse dans l'exploitation minière, impliquant le forage de trous dans la roche, leur chargement en explosifs et le dynamitage pour fragmenter la roche.", category: "Forage et Dynamitage" },
  { term: "Précipitateur Électrostatique", short: "Dispositif de collecte de poussière", definition: "Un dispositif de contrôle de la pollution atmosphérique qui utilise des charges électriques pour éliminer les fines poussières et particules des gaz d'échappement dans les usines de traitement et les fonderies.", category: "Environnement" },
  { term: "Station de Rinçage Oculaire d'Urgence", short: "Point de rinçage chimique des yeux", definition: "Une station d'eau dédiée conçue pour rincer les produits chimiques des yeux en cas de projections. Doit être située dans un délai de 10 secondes de toute zone où des risques oculaires existent et testée hebdomadairement.", category: "Sécurité Minière" },
  { term: "Évaluation d'Impact Environnemental (EIE)", short: "Étude environnementale de la mine", definition: "Une étude formelle évaluant les effets environnementaux potentiels d'un projet minier avant son démarrage, incluant les impacts sur l'eau, l'air, le sol, la biodiversité et les communautés locales.", category: "Environnement" },
  { term: "Limite Explosive", short: "Plage de concentration d'explosion de gaz", definition: "La plage de concentration d'un gaz inflammable dans l'air à l'intérieur de laquelle il peut s'enflammer et exploser. En dessous de la Limite Inférieure d'Explosivité (LIE) ou au-dessus de la Limite Supérieure d'Explosivité (LSE) le gaz ne s'enflammera pas.", category: "Sécurité Minière" },
  { term: "Triangle du Feu", short: "Trois éléments du feu", definition: "Les trois éléments nécessaires au feu : combustible, chaleur et oxygène. Enlever l'un ou l'autre de ces éléments éteint le feu. Comprendre le triangle du feu est fondamental pour la prévention et la suppression des incendies sur les sites miniers.", category: "Sécurité Minière" },
  { term: "Cyanure Libre", short: "Cyanure dissous actif", definition: "La fraction de cyanure dissous dans une solution de traitement disponible pour réagir avec et dissoudre l'or. Les niveaux de cyanure libre dans les résidus doivent être gérés et surveillés pour protéger l'environnement.", category: "Traitement" },
  { term: "Géomécanique", short: "Science des forces sur les roches et sols", definition: "L'étude du comportement mécanique des matériaux géologiques — roche et sol — sous des forces appliquées. Les principes de géomécanique régissent la conception de toutes les excavations minières, systèmes de soutènement et pentes.", category: "Ingénierie" },
  { term: "Récupération par Gravité", short: "Séparation de minerai par densité", definition: "Une méthode de traitement des minéraux qui sépare les minéraux précieux des déchets en fonction des différences de densité spécifique (densité). Largement utilisée pour la récupération de l'or, de l'étain et des diamants.", category: "Traitement" },
  { term: "Stress Thermique (Heat Stress)", short: "Danger de surchauffe corporelle", definition: "Un risque grave pour la santé causé par une exposition prolongée à des températures élevées et à l'humidité dans des environnements souterrains ou à ciel ouvert. Les symptômes incluent des étourdissements, des nausées et la perte de conscience.", category: "Santé et Hygiène" },
  { term: "Exploitation par Mur Haut (Highwall Mining)", short: "Exploitation par chariot à distance", definition: "Une technique d'exploitation à ciel ouvert qui utilise une machine de coupe commandée à distance pour extraire le charbon ou les minéraux des faces de paroi haute exposées sans nécessiter que des travailleurs entrent dans la zone.", category: "Méthodes d'Exploitation" },
  { term: "Lixiviation In Situ", short: "Extraction chimique souterraine", definition: "Une technique minière où une solution de lixiviation est injectée directement dans un corps minéralisé souterrain pour dissoudre les minéraux, qui sont ensuite pompés vers la surface pour récupération — sans excavation physique.", category: "Méthodes d'Exploitation" },
  { term: "Instrumentation", short: "Dispositifs de surveillance de mine", definition: "La collection de capteurs, jauges et dispositifs de surveillance installés dans une mine pour mesurer et enregistrer des conditions telles que les mouvements du sol, la pression d'eau, les niveaux de gaz et les performances des équipements.", category: "Surveillance" },
  { term: "Niveau (Level)", short: "Plancher d'accès souterrain horizontal", definition: "Un travail souterrain horizontal relié à un puits ou une descenderie à une profondeur spécifique. Les niveaux fournissent un accès pour le développement, la production et les services et sont typiquement espacés de 20 à 60 mètres verticalement.", category: "Structures Minières" },
  { term: "Abattage en Longs Trous (Long Hole Stoping)", short: "Méthode de tir profond en trous longs", definition: "Une méthode d'exploitation souterraine où de longs trous de mine sont forés vers le haut ou vers le bas pour dynamiter de grands volumes de minerai en un seul tir. Une méthode productive et rentable pour les grands corps minéralisés bien définis.", category: "Méthodes d'Exploitation" },
  { term: "Fiche Technique de Sécurité (MSDS)", short: "Ancien formulaire de danger chimique", definition: "Le prédécesseur de la moderne Fiche de Données de Sécurité (FDS). Contient des informations sur les dangers, la manipulation et l'intervention d'urgence pour une substance chimique. Le terme MSDS est encore couramment utilisé sur les anciens sites miniers.", category: "Sécurité Minière" },
  { term: "Grillage (Mesh / Wire Mesh)", short: "Revêtement de surface de soutènement", definition: "Panneaux de grillage en acier fixés à la surface de la roche avec des boulons de roche pour retenir les fragments de roche lâche en place et prévenir les chutes de roches mineures dans les excavations souterraines.", category: "Soutènement du Sol" },
  { term: "Zéro Accident (Zero Harm)", short: "Objectif de sécurité zéro blessure", definition: "La philosophie et l'objectif d'atteindre zéro blessure, maladie et décès sur le lieu de travail sur un site minier. Le Zéro Accident est le fondement de la culture de sécurité minière moderne et nécessite l'engagement actif de tout le personnel.", category: "Sécurité Minière" },
  { term: "Zone d'Influence", short: "Rayon d'effet de tir/excavation", definition: "La zone autour d'un tir, d'une excavation ou d'une opération d'engins lourds qui peut être affectée par son activité. Tout le personnel et les équipements doivent être évacués de la zone d'influence avant le dynamitage ou les grands travaux de terrassement.", category: "Sécurité Minière" },
];
